#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAX_VERTICES 100

// Queue structure for BFS
typedef struct {
 int items[MAX_VERTICES];
 int front;
 int rear;
} Queue;

// Adjacency list node
typedef struct Node {
 int vertex;
 struct Node* next;
} Node;

// Graph structure
typedef struct {
 int num_vertices;
 Node* adj_list[MAX_VERTICES];
} Graph;

// Initialize queue
void initQueue(Queue* q) {
 q->front = -1;
 q->rear = -1;
}

// Check if queue is empty
int isEmpty(Queue* q) {
 return q->front == -1;
}

// Enqueue element
void enqueue(Queue* q, int value) {
 if (q->front == -1) {
 q->front = 0;
 }
 q->items[++q->rear] = value;
}

// Dequeue element
int dequeue(Queue* q) {
 return q->items[q->front++];
}

// Create new adjacency list node
Node* createNode(int v) {
 Node* newNode = (Node*)malloc(sizeof(Node));
 newNode->vertex = v;
 newNode->next = NULL;
 return newNode;
}

// Initialize graph
void initGraph(Graph* g, int n) {
 g->num_vertices = n;
 for (int i = 0; i < n; i++) {
 g->adj_list[i] = NULL;
 }
}

// Add undirected edge
void addEdge(Graph* g, int u, int v) {
 // Add v to u's adjacency list
 Node* newNode = createNode(v);
 newNode->next = g->adj_list[u];
 g->adj_list[u] = newNode;

 // Add u to v's adjacency list (undirected)
 newNode = createNode(u);
 newNode->next = g->adj_list[v];
 g->adj_list[v] = newNode;
}

// BFS traversal
void bfsTraversal(Graph* g, int start) {
 int visited[MAX_VERTICES] = {0};
 Queue q;
 initQueue(&q);

 visited[start] = 1;
 enqueue(&q, start);

 printf("BFS Traversal: ");
 while (!isEmpty(&q)) {
 int v = dequeue(&q);
 printf("%d ", v);

 Node* temp = g->adj_list[v];
 while (temp != NULL) {
 if (!visited[temp->vertex]) {
 visited[temp->vertex] = 1;
 enqueue(&q, temp->vertex);
 }
 temp = temp->next;
 }
 }
 printf("\n");
}

// BFS with shortest path distances
void bfsShortestPath(Graph* g, int start) {
 int visited[MAX_VERTICES] = {0};
 int distance[MAX_VERTICES];
 int predecessor[MAX_VERTICES];
 Queue q;
 initQueue(&q);

 // Initialize arrays
 for (int i = 0; i < g->num_vertices; i++) {
 distance[i] = -1; // -1 means unreachable
 predecessor[i] = -1; // No predecessor
 }

 visited[start] = 1;
 distance[start] = 0;
 enqueue(&q, start);

 while (!isEmpty(&q)) {
 int v = dequeue(&q);

 Node* temp = g->adj_list[v];
 while (temp != NULL) {
 if (!visited[temp->vertex]) {
 visited[temp->vertex] = 1;
 distance[temp->vertex] = distance[v] + 1;
 predecessor[temp->vertex] = v;
 enqueue(&q, temp->vertex);
 }
 temp = temp->next;
 }
 }

 // Print distances
 printf("\nVertex\tDistance\tPath from %d\n", start);
 for (int i = 0; i < g->num_vertices; i++) {
 printf("%d\t%d\t\t", i, distance[i]);

 // Reconstruct and print path
 if (distance[i] >= 0) {
 int path[MAX_VERTICES];
 int path_len = 0;
 int current = i;

 while (current != -1) {
 path[path_len++] = current;
 current = predecessor[current];
 }

 // Print in reverse (from start to vertex)
 for (int j = path_len - 1; j >= 0; j--) {
 printf("%d", path[j]);
 if (j > 0) printf(" -> ");
 }
 } else {
 printf("Unreachable");
 }
 printf("\n");
 }
}

int main() {
 Graph g;
 initGraph(&g, 6);

 // Build the graph from the example in content
 addEdge(&g, 0, 1);
 addEdge(&g, 0, 2);
 addEdge(&g, 1, 3);
 addEdge(&g, 1, 5);
 addEdge(&g, 2, 3);
 addEdge(&g, 2, 4);

 // BFS traversal
 bfsTraversal(&g, 0);

 // BFS with shortest path
 bfsShortestPath(&g, 0);

 return 0;
}

import java.util.*;

public class BFSGraph {
 private int numVertices;
 private LinkedList<Integer>[] adjList;

 @SuppressWarnings("unchecked")
 public BFSGraph(int numVertices) {
 this.numVertices = numVertices;
 this.adjList = new LinkedList[numVertices];

 for (int i = 0; i < numVertices; i++) {
 adjList[i] = new LinkedList<>();
 }
 }

 public void addEdge(int u, int v) {
 // Undirected graph
 adjList[u].add(v);
 adjList[v].add(u);
 }

 /**
 * Basic BFS traversal from a given source vertex
 */
 public List<Integer> bfsTraversal(int start) {
 List<Integer> traversal = new ArrayList<>();
 boolean[] visited = new boolean[numVertices];
 Queue<Integer> queue = new LinkedList<>();

 visited[start] = true;
 queue.offer(start);

 while (!queue.isEmpty()) {
 int vertex = queue.poll();
 traversal.add(vertex);

 // Visit all unvisited neighbors
 for (int neighbor : adjList[vertex]) {
 if (!visited[neighbor]) {
 visited[neighbor] = true;
 queue.offer(neighbor);
 }
 }
 }

 return traversal;
 }

 /**
 * BFS that tracks level/distance of each vertex from source
 */
 public Map<Integer, Integer> bfsWithLevels(int start) {
 Map<Integer, Integer> levels = new HashMap<>();
 boolean[] visited = new boolean[numVertices];
 Queue<Integer> queue = new LinkedList<>();

 visited[start] = true;
 levels.put(start, 0);
 queue.offer(start);

 while (!queue.isEmpty()) {
 int vertex = queue.poll();
 int currentLevel = levels.get(vertex);

 for (int neighbor : adjList[vertex]) {
 if (!visited[neighbor]) {
 visited[neighbor] = true;
 levels.put(neighbor, currentLevel + 1);
 queue.offer(neighbor);
 }
 }
 }

 return levels;
 }

 /**
 * Find all connected components using BFS
 */
 public List<List<Integer>> findConnectedComponents() {
 List<List<Integer>> components = new ArrayList<>();
 boolean[] visited = new boolean[numVertices];

 for (int i = 0; i < numVertices; i++) {
 if (!visited[i]) {
 List<Integer> component = new ArrayList<>();
 Queue<Integer> queue = new LinkedList<>();

 visited[i] = true;
 queue.offer(i);

 while (!queue.isEmpty()) {
 int vertex = queue.poll();
 component.add(vertex);

 for (int neighbor : adjList[vertex]) {
 if (!visited[neighbor]) {
 visited[neighbor] = true;
 queue.offer(neighbor);
 }
 }
 }

 components.add(component);
 }
 }

 return components;
 }

 /**
 * BFS shortest path with predecessor tracking
 */
 public Map<Integer, Integer> bfsShortestPath(int start) {
 Map<Integer, Integer> predecessor = new HashMap<>();
 boolean[] visited = new boolean[numVertices];
 Queue<Integer> queue = new LinkedList<>();

 visited[start] = true;
 predecessor.put(start, -1); // -1 indicates no predecessor
 queue.offer(start);

 while (!queue.isEmpty()) {
 int vertex = queue.poll();

 for (int neighbor : adjList[vertex]) {
 if (!visited[neighbor]) {
 visited[neighbor] = true;
 predecessor.put(neighbor, vertex);
 queue.offer(neighbor);
 }
 }
 }

 return predecessor;
 }

 public List<Integer> reconstructPath(Map<Integer, Integer> pred, int start, int target) {
 List<Integer> path = new LinkedList<>();
 int current = target;

 while (current != -1) {
 path.add(0, current); // Add to front
 current = pred.get(current);
 }

 if (path.isEmpty() || path.get(0) != start) {
 return Collections.emptyList(); // No path exists
 }

 return path;
 }

 public static void main(String[] args) {
 BFSGraph graph = new BFSGraph(6);

 // Build graph from example
 graph.addEdge(0, 1);
 graph.addEdge(0, 2);
 graph.addEdge(1, 3);
 graph.addEdge(1, 5);
 graph.addEdge(2, 3);
 graph.addEdge(2, 4);

 // Basic BFS traversal
 System.out.println("BFS Traversal from 0: " + graph.bfsTraversal(0));

 // BFS with levels
 Map<Integer, Integer> levels = graph.bfsWithLevels(0);
 System.out.println("\nVertex Levels from 0:");
 for (Map.Entry<Integer, Integer> entry : levels.entrySet()) {
 System.out.println("Vertex " + entry.getKey() + ": Level " + entry.getValue());
 }

 // Shortest path to vertex 4
 Map<Integer, Integer> predecessor = graph.bfsShortestPath(0);
 List<Integer> path = graph.reconstructPath(predecessor, 0, 4);
 System.out.println("\nShortest path from 0 to 4: " + path);

 // Connected components (for this connected graph)
 System.out.println("\nConnected Components: " + graph.findConnectedComponents());
 }
}
